import json, re
path = var_call_0h1lVBuDoAWrvSOcNhImBEul
with open(path, 'r', encoding='utf-8') as f:
    all_rows = json.load(f)

# find UC publication numbers by scanning rows whose Patents_info mentions Univ California
uc_pub_nums = set()
for rec in all_rows:
    pi = rec.get('Patents_info','')
    if re.search(r'univ(ersity)?\.?\s+california', pi, re.IGNORECASE):
        # find publication-number-like tokens
        for m in re.findall(r"\b[A-Z]{2}-[0-9A-Z\-]+\b", pi):
            uc_pub_nums.add(m)
        # also common US, WO, EP forms
        for m in re.findall(r"\b(US-[0-9A-Z\-]+|WO-[0-9A-Z\-]+|EP-[0-9A-Z\-]+)\b", pi):
            uc_pub_nums.add(m)

# fallback: if empty, try to find any rows where Patents_info contains 'UNIV CALIFORNIA' exactly and parse nearby tokens
if not uc_pub_nums:
    for rec in all_rows:
        pi = rec.get('Patents_info','')
        if 'UNIV CALIFORNIA' in pi.upper():
            for m in re.findall(r"\b[A-Z]{2}-[0-9A-Z\-]+\b", pi):
                uc_pub_nums.add(m)

# Now find publications that cite any of these UC publication numbers
assignee_cpc = {}
for rec in all_rows:
    cit_field = rec.get('citation','')
    try:
        citations = json.loads(cit_field) if cit_field and cit_field.strip().startswith('[') else []
    except Exception:
        citations = []
    cited_pns = {c.get('publication_number') for c in citations if isinstance(c, dict) and c.get('publication_number')}
